src/commands/dice.ts<pre><code>import { register_command } from "./index";

register_command({
  name: "dice",
  description: "Roll a dice",
  aliases: ["roll"],
  async execute({ wa, cid, args }) {
    const sides = parseInt(args[0]) || 6;

