register_command({
  name: "group",
  description: "Group information",
  aliases: ["g"],
  async execute({ wa, cid }) {
    // Only in groups
    if (!cid.endsWith("@g.us")) {
      await wa.Message.text(cid, "This command only works in groups");
      return;
